namespace sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Models;

public sealed class StatusUpdate
{
    public required DateTime Timestamp { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
}

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTime EstimatedDelivery { get; init; }
    public required List<StatusUpdate> Updates { get; init; }
}

using sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Models;

namespace sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Models;

namespace sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Services;

/// <summary>
/// IShipmentService implementation used on WebAssembly — calls the server API over HTTP.
/// </summary>
public sealed class ShipmentHttpClient(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        return await http.GetFromJsonAsync<Shipment>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);
    }
}

using sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Models;
using sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Services;

namespace sv_4cfcaeba85f5454b8e3bc7730a273379.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with seeded data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-1001"] = new Shipment
        {
            TrackingNumber = "PKG-1001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTime(2026, 6, 2),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 25, 8, 0, 0), Status = "Picked Up", Location = "Los Angeles, CA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 26, 3, 15, 0), Status = "Departed Facility", Location = "Los Angeles, CA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 26, 18, 45, 0), Status = "In Transit", Location = "Memphis, TN" },
            ]
        },
        ["PKG-1002"] = new Shipment
        {
            TrackingNumber = "PKG-1002",
            Status = "Delivered",
            Location = "New York, NY",
            EstimatedDelivery = new DateTime(2026, 5, 24),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 21, 10, 0, 0), Status = "Picked Up", Location = "Chicago, IL" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 22, 6, 30, 0), Status = "In Transit", Location = "Columbus, OH" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 23, 14, 0, 0), Status = "Out for Delivery", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 23, 16, 22, 0), Status = "Delivered", Location = "New York, NY" },
            ]
        },
        ["PKG-1003"] = new Shipment
        {
            TrackingNumber = "PKG-1003",
            Status = "Label Created",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTime(2026, 6, 5),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 27, 9, 0, 0), Status = "Label Created", Location = "Seattle, WA" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Models
@using sv_4cfcaeba85f5454b8e3bc7730a273379.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipments> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
        Loading shipment <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p class="mb-2">@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        No shipment found for tracking number <strong>@TrackingNumber</strong>.
    </div>
}
else
{
    <h2>Shipment @_shipment.TrackingNumber</h2>

    <dl class="row">
        <dt class="col-sm-3">Status</dt>
        <dd class="col-sm-9">@_shipment.Status</dd>

        <dt class="col-sm-3">Current Location</dt>
        <dd class="col-sm-9">@_shipment.Location</dd>

        <dt class="col-sm-3">Estimated Delivery</dt>
        <dd class="col-sm-9">@_shipment.EstimatedDelivery.ToShortDateString()</dd>
    </dl>

    <h4>Status Updates</h4>
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Time</th>
                <th>Status</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.Updates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Status</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter] public string TrackingNumber { get; set; } = "";

    private Shipment? _shipment;
    private bool _loading;
    private string? _error;
    private CancellationTokenSource? _cts;

    // Tracks the tracking number that was last loaded so we can detect parameter changes.
    private string _loadedTrackingNumber = "";

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(TrackingNumber, _loadedTrackingNumber, StringComparison.OrdinalIgnoreCase))
            return;

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        CancelPending();

        _loadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _error = null;
        _loading = true;

        var cts = new CancellationTokenSource(TimeSpan.FromSeconds(30));
        _cts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested && !cts.IsCancellationRequested)
        {
            // Cancelled because the user navigated away or the component was disposed — no error to show.
            return;
        }
        catch (OperationCanceledException)
        {
            Logger.LogWarning("Shipment request for {TrackingNumber} timed out", TrackingNumber);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load shipment {TrackingNumber}", TrackingNumber);
            _error = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        _loadedTrackingNumber = "";
        await LoadShipmentAsync();
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

