namespace sv_4cfcaeba85f5454b8e3bc7730a273379.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with seeded data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-1001"] = new Shipment
        {
            TrackingNumber = "PKG-1001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTime(2026, 6, 2),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 25, 8, 0, 0), Status = "Picked Up", Location = "Los Angeles, CA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 26, 3, 15, 0), Status = "Departed Facility", Location = "Los Angeles, CA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 26, 18, 45, 0), Status = "In Transit", Location = "Memphis, TN" },
            ]
        },
        ["PKG-1002"] = new Shipment
        {
            TrackingNumber = "PKG-1002",
            Status = "Delivered",
            Location = "New York, NY",
            EstimatedDelivery = new DateTime(2026, 5, 24),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 21, 10, 0, 0), Status = "Picked Up", Location = "Chicago, IL" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 22, 6, 30, 0), Status = "In Transit", Location = "Columbus, OH" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 23, 14, 0, 0), Status = "Out for Delivery", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 23, 16, 22, 0), Status = "Delivered", Location = "New York, NY" },
            ]
        },
        ["PKG-1003"] = new Shipment
        {
            TrackingNumber = "PKG-1003",
            Status = "Label Created",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTime(2026, 6, 5),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 27, 9, 0, 0), Status = "Label Created", Location = "Seattle, WA" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

